from dataclasses import dataclass
from typing import Optional

@dataclass
class GenAIFeatureSpec:
    feature_name: str
    description: str
    prompt_context_includes_pii: bool
    rag_sources_contain_personal_data: bool
    output_personalised_to_user: bool
    usage_logs_retained: bool
    fine_tuned_on_personal_data: bool

    def processes_personal_data(self) -> bool:
        return any([
            self.prompt_context_includes_pii,
            self.rag_sources_contain_personal_data,
            self.output_personalised_to_user,
            self.usage_logs_retained,
            self.fine_tuned_on_personal_data,
        ])

    def personal_data_categories(self) -> list[str]:
        cats = []
        if self.prompt_context_includes_pii:
            cats.append("user-provided PII in prompts")
        if self.rag_sources_contain_personal_data:
            cats.append("personal data in RAG source documents")
        if self.output_personalised_to_user:
            cats.append("personalised outputs linked to user identity")
        if self.usage_logs_retained:
            cats.append("usage logs (user ID + prompt metadata)")
        if self.fine_tuned_on_personal_data:
            cats.append("personal data in fine-tuning dataset")
        return cats

from dataclasses import dataclass
from enum import Enum

class DPIATrigger(str, Enum):
    SYSTEMATIC_PROFILING = "systematic_profiling_significant_effects"
    SPECIAL_CATEGORY_LARGE_SCALE = "special_category_large_scale"
    PUBLIC_AREA_MONITORING = "public_area_monitoring"
    NOVEL_TECHNOLOGY = "novel_technology"
    RIGHTS_PREVENTION = "prevents_exercise_of_rights"
    DATASET_MATCHING = "dataset_matching_beyond_purpose"

@dataclass
class DPIATriggerAssessment:
    feature_name: str
    triggers_identified: list[DPIATrigger]
    jurisdictions: list[str]   # e.g. ["EU-GDPR", "UK-GDPR", "Brazil-LGPD"]
    assessor: str
    assessed_date: str

    def dpia_mandatory(self) -> bool:
        mandatory_triggers = {
            DPIATrigger.SYSTEMATIC_PROFILING,
            DPIATrigger.SPECIAL_CATEGORY_LARGE_SCALE,
            DPIATrigger.PUBLIC_AREA_MONITORING,
            DPIATrigger.RIGHTS_PREVENTION,
            DPIATrigger.DATASET_MATCHING,
        }
        # Mandatory if any hard trigger, or if 2+ criteria met (Art.35(1) catch-all)
        hard_triggers = mandatory_triggers & set(self.triggers_identified)
        return len(hard_triggers) > 0 or len(self.triggers_identified) >= 2

    def dpia_recommended(self) -> bool:
        return DPIATrigger.NOVEL_TECHNOLOGY in self.triggers_identified

    def outcome(self) -> str:
        if self.dpia_mandatory():
            return "DPIA MANDATORY — must complete before go-live"
        if self.dpia_recommended():
            return "DPIA RECOMMENDED — complete before go-live; document rationale if not"
        return "Lightweight privacy review sufficient — document decision"

    def summary(self) -> str:
        return (
            f"Feature: {self.feature_name} | "
            f"Triggers: {[t.value for t in self.triggers_identified]} | "
            f"Outcome: {self.outcome()}"
        )

from dataclasses import dataclass
from enum import Enum

class AIActRiskCategory(str, Enum):
    UNACCEPTABLE = "unacceptable"    # prohibited — no deployment
    HIGH = "high"                    # Annex III — DPIA + FRIA required
    LIMITED = "limited"              # transparency obligations only
    MINIMAL = "minimal"              # no specific obligations

ANNEX_III_CATEGORIES = [
    "biometric identification",
    "critical infrastructure management",
    "education and vocational training",
    "employment and workforce management",
    "access to essential services (credit, insurance)",
    "law enforcement",
    "migration and asylum",
    "administration of justice",
]

@dataclass
class AIActAssessment:
    feature_name: str
    primary_use_case: str

    def risk_category(self) -> AIActRiskCategory:
        prohibited = ["social scoring", "real-time biometric in public by law enforcement"]
        if any(p in self.primary_use_case.lower() for p in prohibited):
            return AIActRiskCategory.UNACCEPTABLE
        if any(cat in self.primary_use_case.lower() for cat in ANNEX_III_CATEGORIES):
            return AIActRiskCategory.HIGH
        return AIActRiskCategory.MINIMAL

    def requires_fria(self) -> bool:
        return self.risk_category() == AIActRiskCategory.HIGH

    def combined_assessment_needed(self) -> bool:
        return self.requires_fria()  # DPIA + FRIA together

    def assessment_note(self) -> str:
        if self.risk_category() == AIActRiskCategory.UNACCEPTABLE:
            return "Deployment prohibited under EU AI Act Article 5."
        if self.requires_fria():
            return "DPIA + Fundamental Rights Impact Assessment required before deployment."
        return "Standard DPIA trigger assessment applies."
